Prolog:
sPrefix = Trim(pPrefix);
If(sPrefix @= '');
  sPrefix = 'IMF';
EndIf;

sDimensionCode = Trim(pDimensionCode);
sVersionId = Trim(pVersionId);

sDimDimension = sPrefix | '.D.Dimension';
sDimVersion = sPrefix | '.D.Version';
sCubeVersion = sPrefix | '.C.Version';

If((sDimensionCode @= '') % (sVersionId @= ''));
  ProcessBreak;
EndIf;
If(DimensionElementExists(sDimDimension, sDimensionCode) = 0);
  ProcessBreak;
EndIf;
If(DimensionElementExists(sDimVersion, sVersionId) = 0);
  ProcessBreak;
EndIf;

sMasterDimension = Trim(AttrS(sDimDimension, sDimensionCode, 'MasterDimensionName'));
If(sMasterDimension @= '');
  sMasterDimension = sDimensionCode;
EndIf;
If(DimensionExists(sMasterDimension) = 0);
  ProcessBreak;
EndIf;

sArchiveDimension = sMasterDimension | '_ARC_' | TIMST(NOW, '\Y\m\d\h\i\s');

ExecuteProcess(sPrefix | '.P.Dimension.Create',
  'pPrefix', sPrefix,
  'pTargetDimension', sArchiveDimension);

ExecuteProcess(sPrefix | '.P.Dimension.CopyAll',
  'pPrefix', sPrefix,
  'pSourceDimension', sMasterDimension,
  'pTargetDimension', sArchiveDimension,
  'pIncludeData', 'N');

AttrPutS(sArchiveDimension, sDimVersion, sVersionId, 'ArchiveDimension');
CellPutS(sArchiveDimension, sCubeVersion, sVersionId, 'ArchiveDimension');
AttrPutS(sArchiveDimension, sDimDimension, sDimensionCode, 'LastArchivedDimension');
ExecuteProcess(sPrefix | '.P.Log.Event',
  'pPrefix', sPrefix,
  'pSeverity', 'INFO',
  'pObjectType', 'DIMENSION',
  'pObjectName', sArchiveDimension,
  'pMessage', 'Master dimension archived before publish or rollback.',
  'pRunId', sVersionId);
